const input = $input.first().json;

return [{
  json: {
    customer_id: input.customer_id ?? input.user_id ?? input.userId ?? input.phone ?? 'inconnu',
    customer_message: input.customer_message ?? input.message ?? input.chatInput ?? 'Message non fourni',
    reason: input.reason ?? 'Intervention humaine demandée par l’Agent IA',
    human_mode: true,
    requested_at: new Date().toISOString()
  }
}];

const handoff = $('Préparer le transfert').first().json;

return [{
  json: {
    success: true,
    handoff: true,
    human_mode: true,
    customer_id: handoff.customer_id,
    reason: handoff.reason,
    response: 'Je vous transfère à un conseiller humain. Il vous répondra dès que possible.'
  }
}];
